```class Solution {
    public String smallestNumber(String pattern) {
        StringBuilder sb = new StringBuilder();
        int[] digits = new int[9];
        for (int i = 0; i < 9; i++) {
            digits[i] = i + 1;
        }
        for (char c : pattern.toCharArray()) {
            if (c == 'I') {
                for (int i = 0; i < 9; i++) {
                    if (digits[i] > 1) {
                        sb.append(digits[i]);
                        digits[i]--;
                        break;
                    }
                }
            } else {
                for (int i = 8; i >= 0; i--) {
                    if (digits[i] < 9) {
                        sb.append(digits[i] + 1);
                        digits[i]++;
                        break;
                    }
                }
            }
        }
        sb.append(1);
        return sb.toString();
    }
}```
